1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty set of living cells when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a living cell with only one living neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a living cell alive with two living neighbors", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [-1, 0]])).toContainEqual([0, 0]);
16	  });
17	  it.todo("should keep a living cell alive with three living neighbors");
18	  it.todo("should kill a living cell with four living neighbors (overpopulation)");
19	  it.todo("should bring a dead cell to life when it has exactly three living neighbors (reproduction)");
20	  it.todo("should handle living cells with negative coordinates");
21	});
