1	export type Cell = readonly [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean => {
4	  const [x, y] = cell;
5	  const [ox, oy] = other;
6	  const dx = Math.abs(ox - x);
7	  const dy = Math.abs(oy - y);
8	  return (dx !== 0 || dy !== 0) && dx <= 1 && dy <= 1;
9	};
10	
11	const countLivingNeighbors = (cell: Cell, livingCells: readonly Cell[]): number =>
12	  livingCells.filter((other) => isNeighbor(cell, other)).length;
13	
14	const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
15	
16	export const nextGeneration = (livingCells: readonly Cell[]): Cell[] =>
17	  livingCells.filter((cell) => survives(countLivingNeighbors(cell, livingCells)));
